INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Multi-network scheduling$q$, $q$Plan and publish posts to networks including Facebook, Instagram, LinkedIn, X, TikTok, YouTube, and Google Business Profile from one shared calendar.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Bulk composer$q$, $q$Draft and schedule large batches of posts at once, tailoring copy, images, and timing per network from a single composer window.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Workspaces for clients and brands$q$, $q$Separate profiles, calendars, and reports by client or brand into distinct workspaces so agencies can manage multiple accounts without mixing content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Content approval workflows$q$, $q$Route drafts through configurable approval chains so managers or clients can review and sign off before content is published.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Branded client reporting$q$, $q$Generate white-labeled, customizable PDF and dashboard reports summarizing performance for clients or internal stakeholders.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Social monitoring and listening$q$, $q$Track mentions, keywords, and engagement across connected networks in unified monitoring streams, and reply directly from the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Content library$q$, $q$Store and reuse approved copy, images, and templates in a shared library to keep brand assets consistent across campaigns.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$AI-assisted content creation$q$, $q$Use built-in AI tools to draft post copy and generate suggestions, speeding up content production within the composer.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Mobile apps$q$, $q$Manage scheduling, monitoring, and approvals from iOS and Android apps when working away from a desktop.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$User roles and permissions$q$, $q$Assign granular permissions so team members and clients only see and act on the workspaces and profiles relevant to them.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Workspace structure makes managing many client accounts from one login practical for agencies$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Built-in approval workflows and permissions support structured team and client collaboration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Branded, customizable client reporting reduces manual report-building work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Bulk scheduling and content library speed up recurring publishing tasks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Broad network coverage plus mobile apps for managing accounts on the go$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$No permanent free plan, only a time-limited free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Pricing jumps significantly between tiers as workspace and profile limits increase$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Feature set and workflow can feel like more structure than needed for a single small account$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Social listening is more basic than dedicated social intelligence or listening tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Learning curve exists for teams unfamiliar with workspace-based, agency-style tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$What is Sendible used for?$q$, $q$Sendible is used to schedule and publish social media posts, collaborate on content approvals, monitor mentions and engagement, and generate client reports across multiple social networks from one dashboard.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Does Sendible offer a free plan?$q$, $q$Sendible does not offer an ongoing free plan. It provides a 14-day free trial that does not require a credit card, after which a paid subscription is required to continue using the platform.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$How much does Sendible cost?$q$, $q$Sendible's Core plan starts at $29 per month when billed monthly, with higher tiers such as Plus, Premium, and Elite priced higher based on the number of workspaces and social profiles included. Annual billing offers a discount over monthly pricing.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Which social networks does Sendible support?$q$, $q$Sendible supports scheduling and management for networks including Facebook, Instagram, LinkedIn, X, TikTok, YouTube, Google Business Profile, and Bluesky, among others.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Is Sendible good for agencies?$q$, $q$Yes, Sendible is designed with agencies in mind, offering separate workspaces per client, approval workflows for client sign-off, and white-labeled reporting to share results with clients.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Managing multiple client social accounts$q$, $q$Agencies organize each client's profiles, content calendar, and reporting into a dedicated workspace, keeping accounts separate while working from a single login.$q$, $q$Digital marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Coordinating content approvals$q$, $q$Marketing teams draft posts and route them through configurable approval chains so managers or clients can review content before it publishes.$q$, $q$In-house marketing teams and agencies with client sign-off requirements$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Reporting results to clients or stakeholders$q$, $q$Teams generate white-labeled, customizable reports summarizing scheduling activity, engagement, and reach to share with clients or leadership.$q$, $q$Agency account managers and social media managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Monitoring brand mentions and engagement$q$, $q$Social media managers track mentions, keywords, and comments across connected networks in unified streams and respond without switching apps.$q$, $q$Brand and community managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Core$q$, $q$$29/month$q$, $q$Monthly (annual billing available at a discount)$q$, $q$["1 workspace","6 social profiles","Unlimited users","Unlimited scheduling","Standard reports","Bulk scheduling and monitoring"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Plus$q$, $q$$89/month$q$, $q$Monthly (annual billing available at a discount)$q$, $q$["3 workspaces","18 social profiles","Unlimited users","Everything in Core","Assignment and approvals"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Premium$q$, $q$$199/month$q$, $q$Monthly (annual billing available at a discount)$q$, $q$["7 workspaces","42 social profiles","Unlimited users","Everything in Plus","Content libraries","Custom branded reports","Campaigns","Dedicated onboarding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$Elite$q$, $q$$449/month$q$, $q$Monthly (annual billing available at a discount)$q$, $q$["15 workspaces","90 social profiles","Unlimited users","Everything in Premium","Bulk posting dynamic fields","Advanced user permissions"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Sendible is a social media management platform built primarily for agencies and marketing teams that need to run multiple client accounts from a single dashboard. It centralizes scheduling, publishing, monitoring, and reporting across networks like Facebook, Instagram, LinkedIn, X, TikTok, YouTube, Google Business Profile, and Bluesky, aiming to replace a patchwork of native apps, browser tabs, and spreadsheets with one connected workflow that a whole team can share.$q$, $q$The platform was started in London in 2008 by founder Gavin Hammar as a simple cross-posting tool for the handful of social networks that existed at the time, and has since grown into a full-featured suite covering bulk scheduling, content libraries, approval workflows, monitoring streams, and white-labeled client reporting. It was later acquired by Traject in 2021 and continues to operate as a distinct product with its own brand, pricing, and roadmap within that portfolio.$q$, $q$Rather than chasing every emerging social feature or consumer trend, Sendible positions itself around the operational realities of agency work: managing many client workspaces at once, delegating tasks to team members, keeping clients in the loop through structured approvals, and proving the value of the work with branded reports. That agency-first framing shapes most of its pricing tiers, workspace limits, and feature set, and it is the clearest lens for understanding who the product is really built for.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$who-sendible-is-for$q$, $q$Who Sendible Is For$q$, 2, ARRAY[$q$Sendible fits digital marketing agencies juggling several client accounts, since its workspace structure lets teams separate each client's profiles, calendars, and reports while working from one login instead of maintaining separate logins or spreadsheets per client. In-house marketing teams at mid-sized companies managing multiple brands, product lines, or regional pages also tend to find the workspace and profile limits a natural match for how their teams are organized.$q$, $q$Teams that need structured collaboration benefit most, since Sendible includes content approval chains, role-based permissions, and internal notes, which suit organizations where a manager or client must sign off before anything publishes. Social media managers who need to report upward, whether to a paying client or an internal stakeholder, also gain from the built-in branded reporting, since it removes the manual work of assembling screenshots and spreadsheets each month.$q$, $q$Small businesses and solo marketers who need straightforward scheduling across a handful of profiles can use Sendible too, particularly its entry-level Core plan, though many of the platform's differentiators, workspaces, approvals, and client reporting, are really built for multi-client or multi-brand complexity rather than single-account simplicity, so a solo user may only touch a fraction of what the product offers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Individuals or very small teams managing just one or two social profiles may find Sendible more tool than they need, since its pricing and interface are oriented around workspaces, approvals, and multi-client reporting that a single-brand user is unlikely to use. Lighter, cheaper single-account schedulers are often a better fit for that narrower use case, and paying for unused workspace or profile capacity can feel wasteful.$q$, $q$Organizations that want a completely free plan should look elsewhere, since Sendible offers only a time-limited free trial rather than an ongoing no-cost tier. Buyers on a strict budget who need many social profiles may also find the jump in price between tiers steep once profile and workspace counts are exceeded, particularly moving from the Core plan into the higher agency-oriented tiers.$q$, $q$Teams whose priority is deep, native-style analytics or advanced social listening may want a dedicated analytics or listening tool instead, since Sendible's reporting is solid for client-facing summaries but is not built to rival specialist social intelligence or sentiment analysis platforms. Similarly, teams that rarely need approvals or multi-client separation may find simpler tools faster to set up.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Sendible provides a unified content calendar and bulk composer for scheduling posts across supported networks, with previews tailored to each platform's format so teams can catch formatting issues before publishing. Its Smart Queues and RSS or content suggestion tools help teams keep a steady publishing cadence without manually sourcing new material every day, which matters most for agencies running many accounts at once.$q$, $q$Collaboration features include multi-step content approval workflows, internal collaboration notes, and granular user permissions, which let agencies route drafts through clients or managers before anything goes live and keep feedback attached to the post itself rather than scattered across email threads. A shared media and content library keeps brand assets, evergreen copy, and reusable templates organized across workspaces so teams are not rebuilding the same posts from scratch.$q$, $q$On the reporting side, Sendible generates customizable, white-labeled PDF and dashboard reports for clients, alongside social listening and monitoring streams for mentions, keywords, and engagement across connected networks. AI-assisted post writing and image tools help speed up content creation and idea generation, and the platform includes iOS and Android mobile apps so scheduling, monitoring, and approvals can continue when a team member is away from a desktop.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71aee4e7-d181-4086-ac46-c52b1a6ba51e', $q$the-sendible-experience$q$, $q$The Sendible Experience$q$, 2, ARRAY[$q$Day to day, Sendible centers on a dashboard where users build a shared content calendar, drag and drop posts to reschedule, and switch between client workspaces without logging out or juggling separate browser sessions. New users typically start with the 14-day free trial, connect their social profiles, and begin queuing content using the bulk composer or Smart Queue before setting up approval steps for team review as their workflow matures.$q$, $q$The learning curve is moderate: the interface groups scheduling, monitoring, and reporting into distinct sections, which agencies managing many clients tend to appreciate once workspaces, permissions, and approval chains are configured, but which can feel like more structure than a single-user account needs at first. Onboarding resources, help documentation, and support channels are available to guide setup, and the dedicated onboarding included on higher tiers can shorten that ramp-up period further.$q$, $q$Overall, users who lean into the workspace and approval model tend to describe the experience as organized and time-saving for agency operations, cutting down on the back-and-forth of getting client sign-off and assembling reports by hand. Those wanting a minimal single-account scheduler, by contrast, sometimes find the interface heavier than necessary for their needs, since much of the configuration exists to support multi-client complexity they don't have.$q$]::text[], 4);
