INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$ActiveEDR$q$, $q$Autonomous endpoint detection and response that identifies and can act on threats in real time without waiting for analyst review.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Storyline$q$, $q$Automatically correlates related processes, files, and events into a single visual attack timeline for faster root-cause analysis.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$One-click remediation and rollback$q$, $q$Reverses ransomware encryption and other malicious file-system changes, restoring an endpoint to its pre-infection state.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Ranger network discovery$q$, $q$Surfaces unmanaged and rogue devices on the network so unprotected assets can be identified and onboarded.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Purple AI$q$, $q$A generative-AI security assistant that lets analysts investigate telemetry using natural-language queries.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Singularity Cloud Security$q$, $q$Extends protection and posture management to cloud workloads, containers, and Kubernetes environments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Singularity Identity$q$, $q$Detects and responds to attacks targeting Active Directory and other identity infrastructure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Singularity Data Lake$q$, $q$Ingests first- and third-party telemetry to support cross-domain XDR correlation and investigation.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Cross-platform single agent$q$, $q$One lightweight agent covers Windows, macOS, and Linux endpoints, reducing tool sprawl.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Offline autonomous protection$q$, $q$Static and behavioral AI run on-device, allowing detection and response even without a live cloud connection.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Autonomous AI-driven detection and response can act on threats without constant analyst intervention$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$One-click rollback can reverse ransomware damage without a full system reimage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Single lightweight agent covers endpoints, cloud workloads, and identity from one console$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Broad XDR ecosystem with integrations across SIEM, SOAR, and ticketing tools$q$, 3);
