INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Pricing is quote-based and enterprise-oriented, which can be costly for smaller organizations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Breadth of modules and detections can create a steep learning curve for new teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Advanced capabilities such as extended data retention or managed hunting require paid add-ons$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Initial alert tuning is often needed to reduce noise and maximize value$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Buying process typically requires a sales conversation rather than instant self-serve checkout$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Does SentinelOne offer a free trial?$q$, $q$SentinelOne typically offers a demo or trial period arranged through its sales team rather than an instant self-serve signup, so availability and length can vary by request.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$What operating systems and environments does SentinelOne support?$q$, $q$SentinelOne's agent supports Windows, macOS, and Linux endpoints, and the platform extends to cloud workloads, containers, and Kubernetes environments through Singularity Cloud Security.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Is SentinelOne a good fit for small businesses?$q$, $q$SentinelOne is primarily designed for mid-size to large enterprises and MSSPs; very small businesses with only a few devices may find its enterprise pricing and feature depth more than they need.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$How is SentinelOne priced?$q$, $q$SentinelOne uses per-endpoint annual licensing across tiered plans such as Core, Control, Complete, and Commercial, with custom quotes required for larger or Enterprise-tier deployments.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$What is Purple AI?$q$, $q$Purple AI is SentinelOne's generative-AI security assistant that lets analysts query security telemetry using natural language to speed up threat investigation.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Ransomware prevention and automated rollback$q$, $q$Detect ransomware behavior in real time and automatically restore affected endpoints to their pre-infection state, reducing downtime and manual recovery effort.$q$, $q$SOC and IT teams at mid-size to large enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Cloud workload and container protection$q$, $q$Extend threat detection and posture management to cloud workloads, containers, and Kubernetes clusters alongside traditional endpoints.$q$, $q$DevSecOps and cloud infrastructure teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Managed detection and response for client environments$q$, $q$Manage detection, investigation, and response across many customer tenants from a single multi-tenant console.$q$, $q$Managed security service providers and MDR providers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f8f6d9c2-d0cd-4055-9836-236ee79834a7', $q$Compliance-driven endpoint visibility$q$, $q$Maintain centralized visibility, audit trails, and rapid response evidence across endpoints to support regulatory and audit requirements.$q$, $q$Compliance teams in finance, healthcare, and government$q$, 3);
