INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f4b7a227-b58a-4c5d-b4e2-c8b940afb795', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$IT Service Management (ITSM)$q$, $q$Manages incidents, problems, changes, and requests with structured workflows, SLAs, and a configurable service catalog.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$IT Operations Management (ITOM)$q$, $q$Discovers infrastructure, maps service dependencies, and correlates events to speed up root-cause identification.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$Now Assist (Generative AI)$q$, $q$Uses generative AI embedded in workflows to summarize cases, draft knowledge content, and recommend next steps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$App Engine$q$, $q$A low-code environment for building custom applications and forms that reuse existing platform data and workflow logic.$q$, 3);
