INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$Virtual Agent$q$, $q$A conversational chatbot that resolves common requests and routes complex ones to the right human agent.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$Integration Hub$q$, $q$Connects ServiceNow to other enterprise systems through prebuilt connectors, APIs, and a visual flow designer.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$Security Operations$q$, $q$Links vulnerability response and security incident response into the same workflow and prioritization engine.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$Performance Analytics$q$, $q$Delivers dashboards and reporting to track KPIs and workflow performance across departments.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$Highly configurable workflow platform that spans IT, HR, customer service, and custom applications$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dba954e7-42de-4597-adda-d2b1563a9303', $q$Enterprise-grade scalability, governance, and security suited to large, complex organizations$q$, 1);
