INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Dispatch board$q$, $q$A real-time visual scheduling board that shows technician availability, job status, and location so dispatchers can assign the right tech to each call.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Call booking and CRM$q$, $q$Built-in call scripts and customer records help call center staff book jobs consistently and keep a full history of past service for every customer.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Dynamic pricebook$q$, $q$Technicians present flat-rate pricing options for repairs, replacements, and add-ons directly from a mobile pricebook while standing in front of the customer.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Mobile technician app$q$, $q$A companion app lets field technicians view job details, capture photos and signatures, and update job status without returning to the office.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Invoicing and mobile payments$q$, $q$Invoices are generated from completed jobs and customers can pay on-site or online, with payment status synced back to the office in real time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Marketing tools$q$, $q$Campaign tracking, reputation management, and marketing return-on-investment reporting help owners see which channels are actually generating booked jobs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Reporting and business intelligence$q$, $q$Dashboards surface technician performance, revenue trends, and marketing effectiveness across a single location or an entire multi-branch operation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Customer financing$q$, $q$Integrated financing options let customers split the cost of larger jobs, which can help techs close bigger tickets in the field.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Multi-location management$q$, $q$Franchise groups and multi-branch operators can view and manage scheduling, reporting, and performance across locations from one account.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$AI-assisted workflows$q$, $q$AI-driven features assist with tasks such as call summarization and dispatch suggestions, aimed at reducing manual administrative work.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Consolidates scheduling, invoicing, marketing, and reporting into a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Deep feature set purpose-built for trades dispatch workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Mobile app lets technicians manage jobs, pricing, and payments on-site$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Strong reporting for multi-location and franchise operations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Established vendor with structured onboarding and implementation support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Pricing is not published and requires a sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Contract commitments and implementation costs can be significant$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Steep learning curve given the breadth of the platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Likely more than solo operators or very small crews need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Full value requires real time investment in setup, training, and configuration$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Is ServiceTitan free to try?$q$, $q$ServiceTitan does not advertise a free trial or free plan. Access is arranged through its sales process, which includes a demo and a custom quote before signup.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$How much does ServiceTitan cost?$q$, $q$ServiceTitan uses custom, quote-based pricing rather than a published rate card, so cost depends on technician count, selected modules, and contract terms discussed with sales.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$What trades does ServiceTitan support?$q$, $q$It is built for residential and commercial trades such as HVAC, plumbing, electrical, and garage door companies, along with related field service businesses that dispatch technicians for on-site work.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Does ServiceTitan have a mobile app?$q$, $q$Yes, technicians use a companion mobile app to view job details, present pricing, capture signatures, and collect payments while in the field.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Is ServiceTitan suitable for small businesses?$q$, $q$It is generally aimed at established companies with multiple technicians and some administrative staff; very small or solo operations may find it more platform, and expense, than they need.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Multi-technician dispatch operations$q$, $q$Coordinating a live schedule across many technicians, tracking job status from booking through completion, and keeping dispatchers and the field in sync throughout the day.$q$, $q$HVAC, plumbing, and electrical companies with several field technicians$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Multi-location trades franchises$q$, $q$Managing scheduling, pricing, and performance reporting consistently across several branches or franchise locations from a single account.$q$, $q$Franchise groups and multi-branch service companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Field-to-office invoicing and payments$q$, $q$Generating invoices directly from completed jobs and collecting payment on-site or online, with financial data syncing automatically to office and accounting systems.$q$, $q$Office managers and billing staff at service companies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Marketing and customer acquisition tracking$q$, $q$Tracking which marketing campaigns and channels are converting into booked jobs, and using reputation and customer-financing tools to grow repeat and larger-ticket business.$q$, $q$Trades business owners focused on growing call volume and revenue per job$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Starter$q$, $q$Custom pricing - contact sales$q$, $q$Annual contract (quote-based)$q$, $q$["Scheduling and dispatch board","Basic customer records","Mobile technician app access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Essentials$q$, $q$Custom pricing - contact sales$q$, $q$Annual contract (quote-based)$q$, $q$["Everything in Starter","Expanded CRM and reporting","Additional software integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$The Works$q$, $q$Custom pricing - contact sales$q$, $q$Annual contract (quote-based)$q$, $q$["Everything in Essentials","Marketing and reputation tools","Full reporting and multi-location management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ServiceTitan is a cloud-based operating system built specifically for trades businesses such as HVAC, plumbing, electrical, garage door, and other residential and commercial field service companies. Founded in 2012 and headquartered in Glendale, California, the company grew from a scheduling tool into a full business management platform that now spans job booking, dispatch, invoicing, marketing, financing, and financial reporting inside a single system, rather than requiring owners to piece those functions together from separate apps.$q$, $q$The platform is built around the day-to-day workflow of a service business: a call comes in, a customer service representative books the job, a technician is dispatched, the job is priced and completed in the field, and the invoice and payment flow back into the office in real time. That closed loop between the field and the office is the core value proposition, replacing the patchwork of paper tickets, whiteboards, spreadsheets, and disconnected point tools that many trades companies historically relied on to run their day-to-day operations, often with limited visibility into what was actually happening on any given job until it was already closed out.$q$, $q$ServiceTitan went public on the Nasdaq in December 2024, reflecting its scale as one of the larger software vendors focused specifically on the trades industry. It sells almost entirely through a direct sales process rather than self-serve signup, positioning itself as a long-term operating system for a service business rather than a single-purpose scheduling app, and it continues to expand into adjacent areas such as customer financing, marketing, and AI-assisted office workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$who-servicetitan-is-for$q$, $q$Who ServiceTitan Is For$q$, 2, ARRAY[$q$ServiceTitan is built for established residential and commercial field service companies — HVAC, plumbing, electrical, garage door, roofing, and similar trades — that run a dispatch-based operation with multiple technicians in the field on a given day and need a central system to keep the office and the field coordinated.$q$, $q$It tends to fit best at companies that already have some administrative structure in place: an office manager or dispatcher, a defined flat-rate pricing process, and enough call volume that a dedicated CRM, dispatch board, and marketing suite pay for themselves over time. Multi-location franchises and larger independent operators are a natural fit given the platform's reporting, permissioning, and multi-branch management capabilities, particularly when leadership needs to compare performance across branches side by side.$q$, $q$Owners who want to consolidate scheduling, invoicing, marketing, customer financing, and business reporting into one system — rather than stitching together several smaller point tools — are also a strong match, since that consolidation is where ServiceTitan differentiates itself from lighter-weight scheduling apps aimed at smaller operations. Businesses evaluating a long-term technology partner, rather than a quick fix, are the intended buyer.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo operators, very small crews, or businesses just starting out are likely to find ServiceTitan more platform than they currently need. The onboarding process, contract commitments, and per-technician pricing structure are built around businesses with meaningful technician headcount, not a one- or two-truck operation still figuring out its basic processes.$q$, $q$Companies that want transparent, self-serve pricing they can compare instantly online will also find the sales-quote-only model frustrating; ServiceTitan does not publish a public rate card, so evaluating true cost requires a sales conversation and, often, a multi-step demo and onboarding cycle before a final number is known.$q$, $q$Trades outside its core focus, or businesses that need a lightweight, low-commitment tool for basic job scheduling and invoicing, are usually better served by simpler and less expensive field service apps rather than adopting a full operating system. Teams without the administrative bandwidth to manage a detailed pricebook and configuration process may also struggle to see full value from the platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The core of ServiceTitan is its dispatch board and scheduling engine, which gives office staff a live view of every technician, job, and time slot, paired with a call-booking workflow, a customer CRM, and dynamic pricebooks technicians use to build flat-rate quotes on-site rather than calling the office for pricing.$q$, $q$On the financial side, the platform handles invoicing and mobile payment collection alongside integrations with accounting systems, plus reporting dashboards that track technician performance, marketing return on investment, job profitability, and overall business health across one or many locations from a single reporting view, so owners and managers do not need to reconcile numbers from several separate tools.$q$, $q$ServiceTitan also layers in marketing tools, reputation management, customer financing options, and, more recently, AI-assisted capabilities such as call summarization and dispatch recommendations under its broader intelligence initiatives, extending the platform beyond pure scheduling into revenue growth, customer communication, and day-to-day workflow automation for office staff.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$the-servicetitan-experience$q$, $q$The ServiceTitan Experience$q$, 2, ARRAY[$q$Using ServiceTitan day-to-day means working across a web-based office dashboard and a companion mobile app that technicians use in the field to view job details, capture photos and signatures, take payments, and update pricebook line items on-site without calling back to the office for approval.$q$, $q$New customers typically go through a structured onboarding and implementation process with ServiceTitan staff, since the platform's depth means configuring pricebooks, automations, permissions, and integrations takes real setup time rather than a quick self-serve signup that can be completed in an afternoon.$q$, $q$For companies that complete that setup, the experience is generally described as a genuine operating system for the business rather than a single-purpose app, with the tradeoff being a higher cost, a longer contract commitment, and a steeper learning curve than smaller, narrower point solutions offer new users. Ongoing training resources and a user community are available to help staff get more comfortable with the platform as they adopt additional modules over time.$q$]::text[], 4);
