INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Secure client portal$q$, $q$A branded, permission-controlled portal where clients upload, download, and review files without needing an internal account.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Encrypted file storage and sync$q$, $q$AES 256-bit encryption for files at rest and in transit, with sync across desktop and mobile devices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$E-signature and requests$q$, $q$Built-in e-signature collection alongside document, form, and task requests sent directly to clients.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Workflow automation$q$, $q$Automated, repeatable processes for recurring client engagements such as intake, onboarding, or engagement letters.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Granular access controls$q$, $q$Folder- and document-level permissions that determine who can view, edit, download, or share specific content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Office and email integrations$q$, $q$Real-time co-editing with Microsoft Office and plugins for Outlook and Gmail for secure email-based sharing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Industry-specific templates$q$, $q$Pre-built templates for tax engagements and other accounting workflows on higher-tier plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Compliance support$q$, $q$Controls and reporting aimed at HIPAA, FINRA, and SEC recordkeeping requirements for regulated industries.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Virtual data room tools$q$, $q$Watermarking, click-trail activity tracking, and NDA enforcement for M&A, audits, and litigation document rooms.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Desktop and mobile apps$q$, $q$Native apps for syncing and accessing files outside the browser across major platforms.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Purpose-built client portal reduces reliance on email attachments for sensitive document exchange$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Strong emphasis on encryption, permissions, and audit trails for regulated industries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Industry-specific templates and workflows for accounting, legal, and financial services$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Integrates with common tools such as Outlook, Gmail, and Microsoft Office$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Free trial available before committing to a paid plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$No free plan, and per-user pricing rises quickly across tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Seat minimums on most plans make it less practical for very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Higher-tier features such as workflow automation and industry templates are gated behind Premium and above$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Oriented around external client exchanges rather than general internal team collaboration$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Initial setup of permissions, branding, and workflows can require a learning curve$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$What is ShareFile used for?$q$, $q$ShareFile is used to securely share, store, and sync files with clients, collect e-signatures and forms, and run client-facing document workflows, primarily for accounting, legal, healthcare, and financial-services firms.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Does ShareFile offer a free plan?$q$, $q$ShareFile does not offer a permanent free plan; instead it offers a free trial across its paid tiers, which start with the Advanced plan and scale up through Premium, Industry Advantage, and Virtual Data Room.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Who owns ShareFile?$q$, $q$ShareFile is owned by Progress Software, which completed its acquisition of ShareFile in 2024 after the product had previously operated under Citrix.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Is ShareFile suitable for small businesses?$q$, $q$ShareFile can work for small professional-services firms with client-facing document needs, but seat minimums and per-user pricing mean very small teams or casual file-sharing use cases may find it costlier than necessary.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Does ShareFile support e-signatures?$q$, $q$Yes, e-signature collection is built into ShareFile's Premium tier and above, alongside related tools for document, form, and task requests.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Tax season client document collection$q$, $q$Accounting firms use ShareFile's client portal and tax-specific templates to collect, organize, and route client documents during high-volume tax season.$q$, $q$Accounting and tax preparation firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Secure legal document exchange$q$, $q$Law firms share contracts, discovery materials, and signed agreements with clients through an encrypted, permission-controlled portal.$q$, $q$Law firms and legal departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$HIPAA-conscious healthcare file sharing$q$, $q$Healthcare organizations exchange patient-related documents and forms with encryption and access controls suited to regulated environments.$q$, $q$Healthcare providers and practice administrators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$M&A and audit data rooms$q$, $q$Deal teams use the Virtual Data Room tier for watermarking, click-trail tracking, and NDA enforcement during due diligence, audits, or litigation.$q$, $q$M&A advisors, auditors, and litigation teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Advanced$q$, $q$$18.15/user/month (monthly), $16.50/user/month (annual)$q$, $q$Monthly or annual, minimum 3 users$q$, $q$["Encrypted file storage and sharing","Secure email integrations","Real-time Office co-editing","Granular access controls","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Premium$q$, $q$$28.60/user/month (monthly), $26.00/user/month (annual)$q$, $q$Monthly or annual, minimum 3 users$q$, $q$["All Advanced features","E-signature, requests, tasks, and forms","Workflow automation","Enhanced client portal","HIPAA/FINRA/SEC-oriented compliance support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Industry Advantage$q$, $q$$45.83/user/month (monthly), $41.67/user/month (annual)$q$, $q$Monthly or annual, minimum 3 users$q$, $q$["All Premium features","Pre-built tax templates","Bulk client onboarding","Centralized engagement management","Automated engagement letters"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Virtual Data Room$q$, $q$$77.00/user/month (monthly), $69.30/user/month (annual)$q$, $q$Monthly or annual, minimum 5 users$q$, $q$["Granular user permissions and document controls","Real-time activity tracking","Dynamic watermarking","NDA enforcement"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ShareFile is a secure, client-facing file sharing, sync, and e-signature platform built for professional services firms that regularly exchange sensitive documents with clients. The product traces back to 2005 in Raleigh, North Carolina, where it was built and launched before spending years under Citrix ownership as Citrix ShareFile. It was later acquired by Progress Software in 2024, which now develops and markets it as part of a broader portfolio of business productivity and digital-experience products.$q$, $q$At its core, ShareFile pairs encrypted file storage and sharing with a branded client portal, e-signature requests, secure email integrations, and workflow automation, letting firms move documents, forms, and approvals between staff and clients without relying on unsecured email attachments or consumer-grade file-sharing tools. The platform is designed so that clients never need a full internal account to participate, lowering friction on the client side of the relationship while keeping the firm's data under tight, centrally managed control.$q$, $q$The platform is organized into tiered subscription plans, generally labeled Advanced, Premium, Industry Advantage, and Virtual Data Room, each layering on additional automation, compliance features, and industry-specific templates. Higher tiers add capabilities aimed squarely at accounting, legal, healthcare, and financial-services workflows rather than general-purpose team collaboration, and pricing scales per user with minimum seat counts on every plan, reflecting a product built for firms rather than individuals.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$who-sharefile-is-for$q$, $q$Who ShareFile Is For$q$, 2, ARRAY[$q$ShareFile is best suited to accounting firms, law firms, wealth management and financial advisory practices, and healthcare organizations that need to send, receive, and store sensitive client documents under audit trails and access controls. These are industries where a client portal and e-signature workflow replace stacks of email attachments, faxed forms, and physical paperwork that would otherwise create compliance risk and slow down client turnaround times.$q$, $q$Firms with compliance obligations, such as those subject to HIPAA, FINRA, or SEC recordkeeping rules, are a natural fit, since ShareFile's higher-tier plans are built around access logging, granular permissions, and document retention controls rather than generic file storage. IT and operations teams at multi-partner or multi-office firms also benefit from the centralized administration, branding, and permission structure that keeps client data organized consistently across the organization.$q$, $q$It also suits organizations running recurring, high-volume client engagements, such as tax season document collection or M&A due diligence, where bulk client onboarding, pre-built engagement templates, and a dedicated virtual data room tier can standardize a repeatable, document-heavy process across many clients at once. Teams that already rely on Outlook, Gmail, or Microsoft Office day to day will find the integrations reduce the friction of adopting a new client-facing system.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Individuals, freelancers, and very small teams looking for a free or low-cost way to share the occasional file will likely find ShareFile more tool than they need. There is no free plan, seat minimums apply on most tiers, and per-user pricing rises quickly as a team grows, which makes the entry cost hard to justify for a one-person business or a hobby project.$q$, $q$Teams whose primary need is internal collaboration, such as real-time document co-authoring, chat, or project management, are better served by a general-purpose workspace suite; ShareFile is oriented around external, client-facing exchanges rather than day-to-day internal team productivity, so it is not a substitute for an internal knowledge base, messaging tool, or project tracker.$q$, $q$Organizations outside regulated or client-services industries that just need casual cloud storage and sync may also find simpler consumer or prosumer storage tools more cost-effective, since much of ShareFile's pricing premium pays for compliance, client-portal, and workflow features that a general storage use case would not exercise. Budget-constrained teams that don't need e-signature, audit trails, or industry templates may be paying for capability they will rarely, if ever, use.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Central to ShareFile is a branded, secure client portal where firms and their clients can upload, request, and exchange files with encryption at rest and in transit, alongside granular permission controls that determine who can view, download, or edit specific folders and documents. Administrators can apply the firm's own branding to the portal so the client experience feels like an extension of the firm rather than a third-party tool.$q$, $q$Built-in e-signature, request, task, and form tools let firms collect signed documents and structured client information without leaving the platform, while workflow automation and, on higher tiers, AI-assisted document handling aim to reduce manual steps in repetitive client-facing processes such as engagement letters or intake forms. Reporting and basic activity visibility are available even on entry tiers, giving administrators insight into who accessed or actioned a given file.$q$, $q$ShareFile also integrates with everyday tools such as Outlook, Gmail, and Microsoft Office for co-editing and email-based sharing, and ships desktop and mobile apps so staff can sync and access client files outside the browser, alongside plan-specific extras like tax-season templates, dynamic watermarking, and audit-ready activity tracking for sensitive deal rooms. Bulk client onboarding and centralized engagement management on higher tiers further help firms scale the same workflow across many simultaneous client relationships.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$the-sharefile-experience$q$, $q$The ShareFile Experience$q$, 2, ARRAY[$q$Day to day, ShareFile centers on two audiences: internal staff managing folders, permissions, and client requests from an admin-style dashboard, and external clients who interact through a simplified, branded portal to upload documents, sign forms, or respond to requests without needing an account of their own. This split keeps the client side approachable even when the underlying permission and compliance configuration on the firm side is fairly detailed.$q$, $q$Setup typically involves configuring folder structures, branding, and user permissions before rolling access out to clients, and firms on Premium and above can layer in automated workflows or industry templates so that recurring engagements follow a consistent, pre-built process rather than being rebuilt manually each time. Desktop and mobile apps extend the same folder structure and permissions to staff working outside the browser, keeping the experience consistent across devices.$q$, $q$Because the product is aimed at regulated, document-intensive industries, the overall experience leans toward structure and auditability over lightweight simplicity: expect a learning curve around permissions and workflow configuration in exchange for detailed activity logs, compliance-oriented controls, and a client-facing interface that feels more like a secure portal than a casual file-sharing app. Firms that invest the setup time tend to find the payoff in fewer email attachments, clearer audit trails, and a more consistent client experience across every engagement.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
