INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Stories, Epics and Iterations$q$, $q$Organize work using a hierarchy built for software teams, connecting granular tasks to larger initiatives and time-boxed sprints.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Kanban Boards and Backlogs$q$, $q$Visualize work across customizable workflow states while keeping a prioritized backlog of upcoming stories.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Git Integrations$q$, $q$Connect GitHub, GitLab, or Bitbucket so branches, commits, and pull requests automatically update story status.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Automations$q$, $q$Reduce manual upkeep by automating routine actions like status changes and notifications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Roadmaps$q$, $q$Plan and communicate larger initiatives over time with a high-level view above day-to-day execution.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Objectives (OKRs)$q$, $q$Link team-level story work to broader company objectives and key results for alignment tracking.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Reporting and Analytics$q$, $q$Measure velocity, cycle time, and throughput to review team progress over sprints and quarters.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Custom Fields$q$, $q$Tailor stories and workflows to a team's own processes with flexible, configurable fields.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$API Access$q$, $q$Build custom integrations and extend Shortcut's data model using a documented API.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Korey AI Agent$q$, $q$An in-app AI agent designed to assist with planning, triage, and day-to-day work management.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Purpose-built data model (stories, epics, iterations) that maps naturally to how software teams already work$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Tight, native integrations with GitHub, GitLab, and Bitbucket link code activity directly to project tracking$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Free tier available for small teams, lowering the barrier to trying the product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Generally regarded as faster to set up and simpler to learn than heavier enterprise tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Keyboard-friendly, developer-oriented interface designed for speed over deep configuration menus$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Not designed for non-technical departments or general-purpose project management outside software teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Fewer deep customization and governance options than large enterprise tools like Jira or Azure DevOps$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Free plan is capped at a small number of users, limiting its use for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Advanced reporting and administrative controls require moving to higher-priced paid tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Smaller ecosystem of third-party integrations and marketplace apps compared to more established competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Is Shortcut free to use?$q$, $q$Shortcut offers a free plan for teams of up to 10 users with core Kanban, roadmap, and basic reporting features. Larger teams or those needing advanced features must move to a paid Team, Business, or Enterprise plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Was Shortcut previously known as Clubhouse?$q$, $q$Yes. The product launched as Clubhouse in 2014 and was renamed Shortcut in 2021, largely to avoid confusion with the unrelated audio social app also called Clubhouse.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Does Shortcut integrate with GitHub or GitLab?$q$, $q$Yes. Shortcut has native integrations with GitHub, GitLab, and Bitbucket that let commits, branches, and pull requests automatically update the status of linked stories.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Who is Shortcut best suited for?$q$, $q$Shortcut is built for software development teams, including engineers, product managers, and engineering leads, particularly small-to-midsize teams that want agile tracking without heavy administrative overhead.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Does Shortcut offer a free trial for paid plans?$q$, $q$Yes. Shortcut provides a full-access free trial (no credit card required) so teams can evaluate paid-tier features before committing to a subscription.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Agile sprint planning for engineering teams$q$, $q$Teams break down epics into stories, assign them to iterations, and track progress across Kanban workflow states in real time.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Connecting code activity to project tracking$q$, $q$Engineering teams link Git branches and pull requests to stories so status updates automatically as code moves through review and merge.$q$, $q$Developers and engineering leads$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Roadmap and OKR alignment$q$, $q$Product managers use Roadmaps and Objectives to connect day-to-day story work with quarterly company goals and communicate progress to stakeholders.$q$, $q$Product managers and leadership$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Lightweight issue tracking for small startups$q$, $q$Early-stage teams adopt the free tier to manage backlogs and sprints without the setup overhead of larger enterprise project tools.$q$, $q$Startups and small teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Up to 10 users","Kanban boards","Roadmap","Basic reports","Sprints and Docs","GitHub/Slack/Figma integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Team$q$, $q$$8.50/user/month$q$, $q$Annual (monthly billing also available)$q$, $q$["Unlimited users","Advanced reports","Work-in-progress limits","Multiple customizable workflows","Automations","All integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Business$q$, $q$$12/user/month$q$, $q$Annual (monthly billing also available)$q$, $q$["Everything in Team","Objectives and Key Results","Advanced custom fields","Multiple workspaces","Enhanced reporting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, $q$["Everything in Business","Volume discounts","Premier support SLAs","SSO and SCIM","Dedicated Slack channel","Onboarding support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Shortcut is a project management platform designed specifically for software development teams. Originally launched as Clubhouse in 2014, the company rebranded to Shortcut in 2021 after the rise of the unrelated Clubhouse audio app made the original name impractical, though the underlying product and its philosophy stayed consistent throughout the transition.$q$, $q$The core of Shortcut is built around a hierarchy that maps naturally to how engineering teams already think: stories, epics, and iterations. Work moves through customizable workflow states on Kanban-style boards, and teams can organize larger initiatives into epics while grouping day-to-day execution into time-boxed iterations, giving both granular task tracking and higher-level roadmap visibility in one connected system.$q$, $q$Headquartered in New York City, Shortcut operates a freemium pricing model: a free tier supports small teams of up to ten users, while paid Team, Business, and Enterprise tiers unlock unlimited seats, deeper reporting, and administrative controls. The company has more recently added AI-assisted capabilities, including an in-app agent called Korey aimed at helping engineering teams plan and manage work alongside automated assistance.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$who-shortcut-is-for$q$, $q$Who Shortcut Is For$q$, 2, ARRAY[$q$Shortcut is aimed squarely at software development teams rather than general business operations. Startups and small-to-midsize engineering organizations that want an agile tracking tool without the configuration overhead of larger enterprise suites tend to be the best fit, since the product favors sensible defaults over exhaustive customization.$q$, $q$Product managers and engineering leads who want a lightweight way to plan sprints, track epics, and report on velocity without a heavy administrative burden are a natural audience. Teams transitioning off spreadsheets, lightweight Kanban tools, or an overly complex issue tracker often cite simplicity as the reason they move to Shortcut.$q$, $q$Teams already living inside GitHub, GitLab, or Bitbucket benefit most, since Shortcut's Git integrations let commits, branches, and pull requests automatically update story status. This makes it especially appealing to engineering-first organizations that want project management to stay tightly coupled to the actual code being shipped.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Non-technical departments such as marketing, HR, sales, or general operations are unlikely to find Shortcut useful, since its data model and terminology (stories, epics, iterations) are built around software delivery workflows rather than generic task or campaign management.$q$, $q$Very large enterprises with complex cross-departmental governance, extensive compliance workflows, or the need for deeply configurable permission structures across hundreds of teams may find tools like Jira, Azure DevOps, or ServiceNow better suited to that scale, since Shortcut intentionally keeps its administrative surface simpler.$q$, $q$Organizations that need extensive no-code workflow building, elaborate custom field logic, or highly bespoke process automation beyond what Shortcut's built-in automations offer may hit limits. Teams whose primary requirement is maximum configurability over ease of use are likely to outgrow Shortcut's more opinionated approach.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Shortcut is its story, epic, and iteration structure, paired with customizable Kanban boards and backlog views. Teams can define multiple workflows for different squads, apply work-in-progress limits, and keep prioritized backlogs visible alongside active sprint work, all within the same shared workspace.$q$, $q$Integration with version control is a defining feature: GitHub, GitLab, and Bitbucket connections let branch names and pull requests automatically move stories through workflow states. On top of that, Automations reduce manual busywork, Custom Fields let teams tailor stories to their own processes, and Roadmaps provide a higher-level view of planned initiatives over time.$q$, $q$Reporting tools cover velocity, cycle time, and team throughput, while Objectives functionality lets organizations connect day-to-day story work to broader OKRs. A documented API supports custom integrations, and the newer Korey AI agent is positioned to help teams plan, triage, and manage work with less manual overhead.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', $q$the-shortcut-experience$q$, $q$The Shortcut Experience$q$, 2, ARRAY[$q$Shortcut's interface is deliberately fast and keyboard-friendly, a design choice reflected in the product's own name. Common actions like creating stories, moving cards between states, and searching across the workspace are optimized to be done without reaching for the mouse, which resonates with developer users in particular.$q$, $q$New teams typically report a short onboarding curve. Setting up a workspace, connecting a Git provider, and configuring a first workflow can be done in a single sitting, without the lengthy administrative configuration that larger enterprise tools often require before a team can start tracking real work.$q$, $q$Overall, the day-to-day experience leans developer-first: clean visual design, minimal clutter, and a workflow model that mirrors how engineering teams already talk about their work. Compared to more configurable enterprise tools, Shortcut trades some flexibility for speed and a noticeably lower learning curve.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
