INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b1c88fdc-36c0-46b6-b18f-74a4330788d4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Legally binding e-signatures$q$, $q$Collect signatures that comply with major e-signature laws such as ESIGN and eIDAS, with a full audit trail for each completed document.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Reusable templates$q$, $q$Convert frequently sent documents into templates with pre-set fields so they can be reused without rebuilding the layout each time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Bulk sending$q$, $q$Send the same document to a large list of recipients in one action, tracking each recipient's individual completion status.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Document groups$q$, $q$Bundle multiple related documents into a single workflow so signers complete them together as one packet.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$In-document payment requests$q$, $q$Collect payment at the same time a document is signed, without needing a separate invoicing or checkout step.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Mobile apps$q$, $q$Native iOS and Android apps allow documents to be reviewed, signed, and sent from a mobile device.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$API and integrations$q$, $q$Connect SignNow to CRMs, cloud storage, and other business apps such as Salesforce and Google Workspace, or build custom workflows via the API.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Custom branding$q$, $q$Apply company logos and branding to the signing experience on Business Premium and higher plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Advanced reporting and audit trails$q$, $q$Track document status, signer activity, and completion history for compliance and internal recordkeeping.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Per-user pricing is generally lower than several major e-signature competitors at comparable feature levels$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Simple, quick document setup and signing flow for both senders and recipients$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Recipients typically don't need to create an account to sign, reducing completion friction$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Native mobile apps make signing and sending usable from a phone or tablet$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Bulk sending and document groups support repeatable, high-volume workflows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Annual signature invite caps apply even on the top-tier Enterprise plan, with per-invite overage charges beyond that$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$No permanent free plan, only a time-limited free trial$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Advanced workflow automation and document generation require pairing with other airSlate products$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Some administrative and settings screens feel more utilitarian than polished$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Higher-tier features like custom branding and conditional fields are gated behind Business Premium and Enterprise plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Is SignNow free to use?$q$, $q$SignNow does not offer a permanent free plan. It offers a time-limited free trial so users can test the platform before subscribing to one of its paid tiers.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Who owns SignNow?$q$, $q$SignNow is owned by airSlate, a company that provides a broader suite of document workflow and automation tools alongside the SignNow e-signature product.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Are SignNow signatures legally binding?$q$, $q$Yes, SignNow's e-signatures are designed to comply with major electronic signature laws, including ESIGN in the United States and eIDAS in the European Union, and each signed document includes an audit trail.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Does SignNow have a limit on how many documents I can send?$q$, $q$Paid plans include a set number of signature invites per user per year, including on the Enterprise plan; sending beyond that allotment incurs an additional per-invite charge.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Does SignNow have mobile apps?$q$, $q$Yes, SignNow offers native apps for iOS and Android so documents can be sent, reviewed, and signed from a mobile device.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Sales contract signing$q$, $q$Sales teams send proposals and contracts as reusable templates, track signer status in real time, and close deals faster without printing or scanning.$q$, $q$Sales teams and account managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$HR onboarding paperwork$q$, $q$HR departments send offer letters, NDAs, and onboarding forms as templates or document groups so new hires can complete everything in one signing session.$q$, $q$HR and people operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Real estate transaction documents$q$, $q$Agents and brokers send purchase agreements, disclosures, and lease documents for signature, using bulk sending when multiple parties need the same paperwork.$q$, $q$Real estate agents and brokerages$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Client agreements with payment collection$q$, $q$Service businesses attach a payment request to a signed service agreement or invoice so the client pays at the same time they sign.$q$, $q$Small business owners and consultants$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Business$q$, $q$$8/user/month billed annually ($20/user/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Unlimited templates","Set number of signature invites per user/year","Mobile apps","Cloud storage integrations","Basic audit trail"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Business Premium$q$, $q$$15/user/month billed annually ($30/user/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Everything in Business","Bulk sending","Document groups","Signing link sharing","In-document payment requests","Custom branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Enterprise$q$, $q$$30/user/month billed annually ($50/user/month billed monthly)$q$, $q$Monthly or annual$q$, $q$["Everything in Business Premium","Advanced threat protection","Conditional fields","Signer attachments","Advanced reporting dashboard"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$Site License$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Everything in Enterprise","Full API access","CRM/ERP integrations","Qualified electronic signatures","Volume-based discounts"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SignNow is a cloud-based electronic signature and document workflow platform owned by airSlate, built to let individuals and organizations sign, send, and manage legally binding documents from a browser or mobile device. It launched in 2011 and has grown into one of the more affordably positioned players in an e-signature market otherwise dominated by higher-priced enterprise incumbents such as DocuSign and Adobe Acrobat Sign.$q$, $q$At its core, SignNow lets users upload a document, add signature and data fields, and route it to one or more signers, tracking status in real time until every party has completed their part. Reusable templates, bulk sending, and document groups extend this beyond one-off signing into repeatable workflows for onboarding, sales agreements, procurement, and internal approvals, so teams aren't rebuilding the same document layout every time it needs to go out.$q$, $q$As part of airSlate's broader no-code workflow suite, SignNow can be paired with adjacent airSlate products for document generation, PDF editing, and workflow automation, giving growing teams a path to more advanced document processes without switching vendors. That said, it also functions perfectly well as a standalone e-signature tool for teams that only need signing and basic document routing rather than a full workflow automation platform, which keeps the learning curve manageable for smaller organizations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$who-signnow-is-for$q$, $q$Who SignNow Is For$q$, 2, ARRAY[$q$SignNow is best suited to small and mid-sized businesses that need dependable e-signature functionality without paying enterprise e-signature prices. Its per-user, per-month pricing, rather than per-envelope or per-signature pricing on most tiers, makes costs predictable for teams that send a steady but moderate volume of documents each month.$q$, $q$Sales teams, HR departments, real estate agents, and legal or operations staff who regularly send contracts, offer letters, NDAs, and agreements tend to get the most value, particularly once they set up reusable templates and bulk-send workflows so the same document doesn't have to be rebuilt for every recipient. Remote and distributed teams also benefit, since the entire signing process happens online without anyone needing to print, scan, or mail paperwork.$q$, $q$It also appeals to organizations already invested in the broader airSlate ecosystem, or to budget-conscious teams evaluating alternatives to DocuSign or Adobe Acrobat Sign, since SignNow's Business and Business Premium tiers typically undercut those competitors on list price while still covering the fundamentals of sending, signing, and tracking documents. Freelancers and solo practitioners who need occasional but professional-looking signing links can also make the entry-level plan work well.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$High-volume senders should read the fine print carefully: SignNow's plans, including Enterprise, cap included signature invites per user per year, with additional sends billed per invite. Organizations that send documents in large batches regularly, such as staffing agencies or high-volume retail operations, may find this cap adds unpredictable cost on top of the subscription fee once they exceed the allotment.$q$, $q$Teams that need the deepest workflow automation, document generation, or advanced conditional-logic capabilities may outgrow SignNow's native feature set and end up needing to add other airSlate products or look at more workflow-centric platforms altogether, since SignNow itself is scoped primarily around signing and light document routing rather than full business-process automation.$q$, $q$There is no permanent free plan, only a time-limited free trial, so anyone looking for an indefinite no-cost e-signature tool for very occasional personal use will need to look elsewhere or budget for a paid subscription once the trial ends. Organizations with strict, highly specialized compliance requirements should also confirm SignNow meets their specific regulatory needs before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$SignNow's core toolset covers legally binding e-signatures, drag-and-drop field placement for signatures, initials, dates, text, and checkboxes, reusable templates, and bulk sending so a single document can go out to many recipients at once. Document groups let related files be routed and tracked together as a single signing workflow instead of managing several separate documents by hand.$q$, $q$Higher tiers add business-oriented capabilities such as payment requests embedded in signed documents, custom branding on the signing experience, conditional fields that adapt a form based on earlier answers, signer attachments for supporting files, and audit trails with detailed activity and completion reporting for compliance and recordkeeping purposes.$q$, $q$SignNow also offers native iOS and Android apps for signing and sending on the go, an API and integrations with tools like Salesforce, Google Workspace, and popular cloud storage providers such as Dropbox and Box, and administrative controls for managing users, teams, and permissions across an organization's account. Qualified electronic signatures and additional compliance options are available on the top-tier Site License plan for regulated industries.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c7ccbb6-c9e7-4107-95f8-8f87d5e67f00', $q$the-signnow-experience$q$, $q$The SignNow Experience$q$, 2, ARRAY[$q$Day to day, SignNow's interface is oriented around speed: uploading a document, dropping in fields, and sending for signature is a fairly quick, guided process, and the mobile apps mirror this closely so documents can be reviewed and signed from a phone without much friction, which matters for signers who are on the move or reviewing paperwork outside the office.$q$, $q$The signing side of the experience is deliberately lightweight for recipients, who typically don't need an account to review and sign a document, which reduces drop-off compared to tools that force recipients through account creation before they can complete a signature. Notifications and reminders help keep pending documents from stalling in someone's inbox.$q$, $q$Administrators managing multiple users will spend more time in the account and team settings, where branding, user roles, and integration configuration live; this layer feels more utilitarian than polished, which is consistent with SignNow's positioning as a value-focused alternative rather than the most design-forward option in its category. Overall, the experience prioritizes getting documents signed quickly over visual flourish.$q$]::text[], 4);
